// Grid-based Bomberman game logic

export const GRID_W = 13;
export const GRID_H = 11;
export const CELL_SIZE = 1.0;

export enum CellType {
  Empty = 0,
  HardBlock = 1,
  SoftBlock = 2,
  Bomb = 3,
  Explosion = 4,
  PowerUp = 5,
}

export enum PowerUpType {
  ExtraBomb = 0,
  BlastRange = 1,
  Speed = 2,
  PassThrough = 3,
  RemoteDetonate = 4,
  Shield = 5,
}

export enum GameState {
  Menu = 0,
  Playing = 1,
  Paused = 2,
  GameOver = 3,
  Victory = 4,
}

export enum GameMode {
  Classic = 0,
  Timed = 1,
  Survival = 2,
  Puzzle = 3,
}

export interface BombData {
  x: number;
  y: number;
  timer: number;
  range: number;
  owner: 'player' | 'enemy';
  remote: boolean;
}

export interface ExplosionData {
  x: number;
  y: number;
  timer: number;
}

export interface EnemyData {
  x: number;
  y: number;
  targetX: number;
  targetY: number;
  moveTimer: number;
  moveSpeed: number;
  alive: boolean;
  type: 'wander' | 'chase' | 'bomber';
  visualX: number;
  visualY: number;
  bombCooldown: number;
}

export interface PowerUpData {
  x: number;
  y: number;
  type: PowerUpType;
  collected: boolean;
}

export class GameManager {
  grid: CellType[][] = [];
  bombs: BombData[] = [];
  explosions: ExplosionData[] = [];
  enemies: EnemyData[] = [];
  powerUps: PowerUpData[] = [];

  playerX = 1;
  playerY = 1;
  playerVisualX = 1;
  playerVisualY = 1;
  playerMoveTimer = 0;

  maxBombs = 1;
  activeBombs = 0;
  blastRange = 2;
  speed = 4.0;
  hasPassThrough = false;
  hasRemoteDetonate = false;
  hasShield = false;
  shieldTimer = 0;

  score = 0;
  level = 1;
  lives = 3;
  enemiesKilled = 0;
  blocksDestroyed = 0;
  timeElapsed = 0;
  timeLimit = 180;
  comboCount = 0;
  comboTimer = 0;

  state = GameState.Menu;
  mode = GameMode.Classic;

  // Achievement tracking
  achievements: string[] = [];
  totalGames = 0;
  totalScore = 0;
  bestScore = 0;
  maxCombo = 0;
  totalEnemiesKilled = 0;
  perfectClears = 0;

  // Settings
  sfxVolume = 0.7;
  musicVolume = 0.5;
  difficulty = 1; // 0=easy, 1=normal, 2=hard

  // Theme
  themeIndex = 0;
  themes = [
    { name: 'Neon Grid', floorColor: 0x001122, gridColor: 0x00ffff, accentColor: 0xff00ff },
    { name: 'Cyber Punk', floorColor: 0x110022, gridColor: 0xff00ff, accentColor: 0x00ff88 },
    { name: 'Solar Flare', floorColor: 0x221100, gridColor: 0xff8800, accentColor: 0xffcc00 },
    { name: 'Deep Space', floorColor: 0x000811, gridColor: 0x4488ff, accentColor: 0x88ccff },
    { name: 'Toxic Glow', floorColor: 0x002200, gridColor: 0x00ff44, accentColor: 0x88ff00 },
  ];

  get currentTheme() { return this.themes[this.themeIndex]; }

  initGrid() {
    this.grid = [];
    for (let y = 0; y < GRID_H; y++) {
      this.grid[y] = [];
      for (let x = 0; x < GRID_W; x++) {
        // Hard blocks in alternating pattern (classic Bomberman)
        if (x % 2 === 0 && y % 2 === 0) {
          this.grid[y][x] = CellType.HardBlock;
        } else {
          this.grid[y][x] = CellType.Empty;
        }
      }
    }

    // Fill with soft blocks (leave corners clear for spawns)
    const clearZones = [
      [1, 1], [2, 1], [1, 2], // Player spawn (top-left)
      [GRID_W - 2, 1], [GRID_W - 3, 1], [GRID_W - 2, 2], // Enemy spawn TR
      [1, GRID_H - 2], [2, GRID_H - 2], [1, GRID_H - 3], // Enemy spawn BL
      [GRID_W - 2, GRID_H - 2], [GRID_W - 3, GRID_H - 2], [GRID_W - 2, GRID_H - 3], // Enemy spawn BR
    ];

    const softBlockDensity = 0.4 + this.difficulty * 0.1;

    for (let y = 0; y < GRID_H; y++) {
      for (let x = 0; x < GRID_W; x++) {
        if (this.grid[y][x] !== CellType.Empty) continue;
        if (x === 0 || x === GRID_W - 1 || y === 0 || y === GRID_H - 1) {
          this.grid[y][x] = CellType.HardBlock; // Border walls
          continue;
        }
        if (clearZones.some(([cx, cy]) => cx === x && cy === y)) continue;
        if (Math.random() < softBlockDensity) {
          this.grid[y][x] = CellType.SoftBlock;
        }
      }
    }
  }

  spawnEnemies() {
    this.enemies = [];
    const count = 2 + this.level + this.difficulty;
    const spawns = [
      { x: GRID_W - 2, y: 1 },
      { x: 1, y: GRID_H - 2 },
      { x: GRID_W - 2, y: GRID_H - 2 },
      { x: Math.floor(GRID_W / 2), y: 1 },
      { x: Math.floor(GRID_W / 2), y: GRID_H - 2 },
      { x: 1, y: Math.floor(GRID_H / 2) },
      { x: GRID_W - 2, y: Math.floor(GRID_H / 2) },
    ];

    const types: Array<'wander' | 'chase' | 'bomber'> = ['wander', 'chase', 'bomber'];
    for (let i = 0; i < Math.min(count, spawns.length); i++) {
      const sp = spawns[i];
      const type = types[i % types.length];
      this.enemies.push({
        x: sp.x, y: sp.y,
        targetX: sp.x, targetY: sp.y,
        moveTimer: 0,
        moveSpeed: 0.8 + this.difficulty * 0.3 + (type === 'chase' ? 0.3 : 0),
        alive: true,
        type,
        visualX: sp.x, visualY: sp.y,
        bombCooldown: 0,
      });
    }
  }

  startGame(mode: GameMode = GameMode.Classic) {
    this.mode = mode;
    this.state = GameState.Playing;
    this.score = 0;
    this.level = 1;
    this.lives = mode === GameMode.Survival ? 1 : 3;
    this.enemiesKilled = 0;
    this.blocksDestroyed = 0;
    this.timeElapsed = 0;
    this.timeLimit = mode === GameMode.Timed ? 120 : 9999;
    this.maxBombs = 1;
    this.activeBombs = 0;
    this.blastRange = 2;
    this.speed = 4.0;
    this.hasPassThrough = false;
    this.hasRemoteDetonate = false;
    this.hasShield = false;
    this.shieldTimer = 0;
    this.comboCount = 0;
    this.comboTimer = 0;
    this.bombs = [];
    this.explosions = [];
    this.powerUps = [];
    this.totalGames++;

    this.playerX = 1;
    this.playerY = 1;
    this.playerVisualX = 1;
    this.playerVisualY = 1;
    this.playerMoveTimer = 0;

    this.initGrid();
    this.spawnEnemies();
  }

  nextLevel() {
    this.level++;
    this.bombs = [];
    this.explosions = [];
    this.powerUps = [];
    this.activeBombs = 0;
    this.playerX = 1;
    this.playerY = 1;
    this.playerVisualX = 1;
    this.playerVisualY = 1;
    this.playerMoveTimer = 0;

    this.initGrid();
    this.spawnEnemies();

    // Level bonus
    this.score += this.level * 500;
    this.checkAchievements();
  }

  canMove(x: number, y: number): boolean {
    if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return false;
    const cell = this.grid[y][x];
    if (cell === CellType.HardBlock) return false;
    if (cell === CellType.SoftBlock && !this.hasPassThrough) return false;
    if (cell === CellType.Bomb) return false;
    return true;
  }

  movePlayer(dx: number, dy: number, delta: number): boolean {
    if (this.state !== GameState.Playing) return false;
    if (this.playerMoveTimer > 0) return false;

    const nx = this.playerX + dx;
    const ny = this.playerY + dy;
    if (!this.canMove(nx, ny)) return false;

    this.playerX = nx;
    this.playerY = ny;
    this.playerMoveTimer = 1.0 / this.speed;

    // Check power-up pickup
    const pIdx = this.powerUps.findIndex(p => p.x === nx && p.y === ny && !p.collected);
    if (pIdx >= 0) {
      this.collectPowerUp(pIdx);
    }

    // Check enemy collision
    this.checkPlayerEnemyCollision();

    return true;
  }

  placeBomb(): boolean {
    if (this.state !== GameState.Playing) return false;
    if (this.activeBombs >= this.maxBombs) return false;
    if (this.bombs.some(b => b.x === this.playerX && b.y === this.playerY)) return false;

    this.bombs.push({
      x: this.playerX,
      y: this.playerY,
      timer: 3.0,
      range: this.blastRange,
      owner: 'player',
      remote: this.hasRemoteDetonate,
    });
    this.grid[this.playerY][this.playerX] = CellType.Bomb;
    this.activeBombs++;
    return true;
  }

  detonateRemote() {
    const remote = this.bombs.find(b => b.remote && b.owner === 'player');
    if (remote) {
      remote.timer = 0;
    }
  }

  update(delta: number): { exploded: BombData[], destroyed: Array<{x: number, y: number}>, powerUpsSpawned: PowerUpData[], enemiesHit: EnemyData[], playerHit: boolean, levelComplete: boolean } {
    const result = {
      exploded: [] as BombData[],
      destroyed: [] as Array<{x: number, y: number}>,
      powerUpsSpawned: [] as PowerUpData[],
      enemiesHit: [] as EnemyData[],
      playerHit: false,
      levelComplete: false,
    };

    if (this.state !== GameState.Playing) return result;

    this.timeElapsed += delta;
    if (this.playerMoveTimer > 0) this.playerMoveTimer -= delta;
    if (this.shieldTimer > 0) this.shieldTimer -= delta;
    if (this.comboTimer > 0) {
      this.comboTimer -= delta;
      if (this.comboTimer <= 0) this.comboCount = 0;
    }

    // Timed mode check
    if (this.mode === GameMode.Timed && this.timeElapsed >= this.timeLimit) {
      this.state = GameState.GameOver;
      this.updateStats();
      return result;
    }

    // Interpolate player visual position
    const lerpSpeed = 12;
    this.playerVisualX += (this.playerX - this.playerVisualX) * Math.min(1, lerpSpeed * delta);
    this.playerVisualY += (this.playerY - this.playerVisualY) * Math.min(1, lerpSpeed * delta);

    // Update bombs
    for (let i = this.bombs.length - 1; i >= 0; i--) {
      const bomb = this.bombs[i];
      bomb.timer -= delta;
      if (bomb.timer <= 0) {
        result.exploded.push(bomb);
        this.explodeBomb(bomb, result);
        this.bombs.splice(i, 1);
        if (bomb.owner === 'player') this.activeBombs--;
      }
    }

    // Update explosions
    for (let i = this.explosions.length - 1; i >= 0; i--) {
      this.explosions[i].timer -= delta;
      if (this.explosions[i].timer <= 0) {
        const exp = this.explosions[i];
        if (this.grid[exp.y][exp.x] === CellType.Explosion) {
          this.grid[exp.y][exp.x] = CellType.Empty;
        }
        this.explosions.splice(i, 1);
      }
    }

    // Update enemies
    this.updateEnemies(delta, result);

    // Check level complete
    if (this.enemies.every(e => !e.alive)) {
      if (this.mode === GameMode.Survival) {
        this.nextLevel();
      } else {
        result.levelComplete = true;
        if (this.level >= 5 + this.difficulty * 2) {
          this.state = GameState.Victory;
          this.score += 5000;
        } else {
          this.nextLevel();
        }
      }
    }

    return result;
  }

  private explodeBomb(bomb: BombData, result: { destroyed: Array<{x: number, y: number}>, powerUpsSpawned: PowerUpData[], enemiesHit: EnemyData[], playerHit: boolean }) {
    const dirs = [[0, 0], [1, 0], [-1, 0], [0, 1], [0, -1]];
    const explosionCells: Array<{x: number, y: number}> = [];

    for (const [dx, dy] of dirs) {
      for (let r = 0; r <= bomb.range; r++) {
        if (dx === 0 && dy === 0 && r > 0) break;
        const ex = bomb.x + dx * r;
        const ey = bomb.y + dy * r;
        if (ex < 0 || ex >= GRID_W || ey < 0 || ey >= GRID_H) break;

        const cell = this.grid[ey][ex];
        if (cell === CellType.HardBlock) break;

        if (cell === CellType.SoftBlock) {
          this.grid[ey][ex] = CellType.Explosion;
          result.destroyed.push({ x: ex, y: ey });
          this.blocksDestroyed++;
          this.score += 10;
          this.comboCount++;
          this.comboTimer = 2.0;
          if (this.comboCount > this.maxCombo) this.maxCombo = this.comboCount;

          // Chance to drop power-up
          if (Math.random() < 0.3) {
            const types = [PowerUpType.ExtraBomb, PowerUpType.BlastRange, PowerUpType.Speed,
              PowerUpType.PassThrough, PowerUpType.RemoteDetonate, PowerUpType.Shield];
            const weights = [3, 3, 2, 1, 1, 1];
            const total = weights.reduce((a, b) => a + b, 0);
            let rnd = Math.random() * total;
            let pType = types[0];
            for (let ti = 0; ti < types.length; ti++) {
              rnd -= weights[ti];
              if (rnd <= 0) { pType = types[ti]; break; }
            }
            const pu: PowerUpData = { x: ex, y: ey, type: pType, collected: false };
            this.powerUps.push(pu);
            result.powerUpsSpawned.push(pu);
          }
          break; // Stop propagation at destroyed block
        }

        if (cell === CellType.Bomb) {
          // Chain explosion
          const chainBomb = this.bombs.find(b => b.x === ex && b.y === ey);
          if (chainBomb) chainBomb.timer = 0;
        }

        this.grid[ey][ex] = CellType.Explosion;
        explosionCells.push({ x: ex, y: ey });
      }
    }

    for (const cell of explosionCells) {
      this.explosions.push({ x: cell.x, y: cell.y, timer: 0.5 });
    }

    // Check player hit
    if (explosionCells.some(c => c.x === this.playerX && c.y === this.playerY)) {
      if (this.hasShield && this.shieldTimer > 0) {
        this.hasShield = false;
        this.shieldTimer = 0;
      } else {
        result.playerHit = true;
        this.lives--;
        if (this.lives <= 0) {
          this.state = GameState.GameOver;
          this.updateStats();
        } else {
          // Respawn at safe spot
          this.playerX = 1;
          this.playerY = 1;
          this.playerVisualX = 1;
          this.playerVisualY = 1;
          this.shieldTimer = 3.0; // Brief invincibility
          this.hasShield = true;
        }
      }
    }

    // Check enemies hit
    for (const enemy of this.enemies) {
      if (!enemy.alive) continue;
      const ex = Math.round(enemy.visualX);
      const ey = Math.round(enemy.visualY);
      if (explosionCells.some(c => c.x === ex && c.y === ey)) {
        enemy.alive = false;
        this.enemiesKilled++;
        this.totalEnemiesKilled++;
        const baseScore = enemy.type === 'bomber' ? 300 : enemy.type === 'chase' ? 200 : 100;
        this.score += baseScore * (1 + this.comboCount * 0.5);
        this.comboCount++;
        this.comboTimer = 2.0;
        result.enemiesHit.push(enemy);
      }
    }

    this.score += this.comboCount > 1 ? this.comboCount * 50 : 0;
    this.checkAchievements();
  }

  private updateEnemies(delta: number, result: { enemiesHit: EnemyData[], playerHit: boolean }) {
    for (const enemy of this.enemies) {
      if (!enemy.alive) continue;

      enemy.moveTimer -= delta;
      if (enemy.bombCooldown > 0) enemy.bombCooldown -= delta;

      // Interpolate visual position
      enemy.visualX += (enemy.x - enemy.visualX) * Math.min(1, 8 * delta);
      enemy.visualY += (enemy.y - enemy.visualY) * Math.min(1, 8 * delta);

      if (enemy.moveTimer <= 0) {
        enemy.moveTimer = 1.0 / enemy.moveSpeed;

        if (enemy.type === 'chase') {
          // Move toward player
          const dx = this.playerX - enemy.x;
          const dy = this.playerY - enemy.y;
          const moves: Array<[number, number]> = [];
          if (Math.abs(dx) >= Math.abs(dy)) {
            moves.push([Math.sign(dx), 0], [0, Math.sign(dy) || 1]);
          } else {
            moves.push([0, Math.sign(dy)], [Math.sign(dx) || 1, 0]);
          }
          moves.push([-Math.sign(dx) || 1, 0], [0, -Math.sign(dy) || 1]);

          let moved = false;
          for (const [mx, my] of moves) {
            const nx = enemy.x + mx;
            const ny = enemy.y + my;
            if (this.canMoveEnemy(nx, ny)) {
              enemy.x = nx;
              enemy.y = ny;
              moved = true;
              break;
            }
          }
          if (!moved) {
            // Random fallback
            this.randomMoveEnemy(enemy);
          }
        } else if (enemy.type === 'bomber') {
          // Move randomly but place bombs
          this.randomMoveEnemy(enemy);
          if (enemy.bombCooldown <= 0 && Math.random() < 0.3) {
            this.placeEnemyBomb(enemy);
            enemy.bombCooldown = 4.0;
          }
        } else {
          // Wander randomly
          this.randomMoveEnemy(enemy);
        }

        // Check collision with player
        if (enemy.x === this.playerX && enemy.y === this.playerY) {
          if (this.hasShield && this.shieldTimer > 0) {
            this.hasShield = false;
            this.shieldTimer = 0;
          } else {
            result.playerHit = true;
            this.lives--;
            if (this.lives <= 0) {
              this.state = GameState.GameOver;
              this.updateStats();
            } else {
              this.playerX = 1;
              this.playerY = 1;
              this.playerVisualX = 1;
              this.playerVisualY = 1;
              this.shieldTimer = 3.0;
              this.hasShield = true;
            }
          }
        }
      }
    }
  }

  private canMoveEnemy(x: number, y: number): boolean {
    if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return false;
    const cell = this.grid[y][x];
    return cell === CellType.Empty || cell === CellType.PowerUp;
  }

  private randomMoveEnemy(enemy: EnemyData) {
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    const shuffled = dirs.sort(() => Math.random() - 0.5);
    for (const [dx, dy] of shuffled) {
      const nx = enemy.x + dx;
      const ny = enemy.y + dy;
      if (this.canMoveEnemy(nx, ny)) {
        enemy.x = nx;
        enemy.y = ny;
        return;
      }
    }
  }

  private placeEnemyBomb(enemy: EnemyData) {
    if (this.bombs.some(b => b.x === enemy.x && b.y === enemy.y)) return;
    this.bombs.push({
      x: enemy.x, y: enemy.y,
      timer: 3.5,
      range: 1 + this.difficulty,
      owner: 'enemy',
      remote: false,
    });
    this.grid[enemy.y][enemy.x] = CellType.Bomb;
  }

  private collectPowerUp(index: number) {
    const pu = this.powerUps[index];
    pu.collected = true;
    this.score += 50;

    switch (pu.type) {
      case PowerUpType.ExtraBomb:
        this.maxBombs = Math.min(this.maxBombs + 1, 8);
        break;
      case PowerUpType.BlastRange:
        this.blastRange = Math.min(this.blastRange + 1, 8);
        break;
      case PowerUpType.Speed:
        this.speed = Math.min(this.speed + 0.5, 8);
        break;
      case PowerUpType.PassThrough:
        this.hasPassThrough = true;
        break;
      case PowerUpType.RemoteDetonate:
        this.hasRemoteDetonate = true;
        break;
      case PowerUpType.Shield:
        this.hasShield = true;
        this.shieldTimer = 15;
        break;
    }
  }

  private checkPlayerEnemyCollision() {
    for (const enemy of this.enemies) {
      if (!enemy.alive) continue;
      if (enemy.x === this.playerX && enemy.y === this.playerY) {
        if (this.hasShield && this.shieldTimer > 0) {
          this.hasShield = false;
          this.shieldTimer = 0;
        } else {
          this.lives--;
          if (this.lives <= 0) {
            this.state = GameState.GameOver;
            this.updateStats();
          } else {
            this.playerX = 1;
            this.playerY = 1;
            this.playerVisualX = 1;
            this.playerVisualY = 1;
            this.shieldTimer = 3.0;
            this.hasShield = true;
          }
        }
        break;
      }
    }
  }

  private updateStats() {
    if (this.score > this.bestScore) this.bestScore = this.score;
    this.totalScore += this.score;
    if (this.enemies.every(e => !e.alive) && this.lives > 0) {
      this.perfectClears++;
    }
  }

  checkAchievements() {
    const checks: Array<{ id: string; name: string; cond: () => boolean }> = [
      { id: 'first_blood', name: 'First Blood', cond: () => this.totalEnemiesKilled >= 1 },
      { id: 'bomber_10', name: 'Demolition Expert', cond: () => this.blocksDestroyed >= 50 },
      { id: 'combo_3', name: 'Chain Reaction', cond: () => this.maxCombo >= 3 },
      { id: 'combo_5', name: 'Combo Master', cond: () => this.maxCombo >= 5 },
      { id: 'combo_10', name: 'Combo Legend', cond: () => this.maxCombo >= 10 },
      { id: 'score_5k', name: 'Score: 5000', cond: () => this.score >= 5000 },
      { id: 'score_10k', name: 'Score: 10000', cond: () => this.score >= 10000 },
      { id: 'score_50k', name: 'Score: 50000', cond: () => this.score >= 50000 },
      { id: 'level_3', name: 'Intermediate', cond: () => this.level >= 3 },
      { id: 'level_5', name: 'Veteran', cond: () => this.level >= 5 },
      { id: 'level_10', name: 'Master Bomber', cond: () => this.level >= 10 },
      { id: 'kill_10', name: 'Hunter', cond: () => this.totalEnemiesKilled >= 10 },
      { id: 'kill_50', name: 'Exterminator', cond: () => this.totalEnemiesKilled >= 50 },
      { id: 'kill_100', name: 'Genocide', cond: () => this.totalEnemiesKilled >= 100 },
      { id: 'perfect', name: 'Perfect Clear', cond: () => this.perfectClears >= 1 },
      { id: 'games_10', name: 'Dedicated', cond: () => this.totalGames >= 10 },
      { id: 'speed_max', name: 'Speed Demon', cond: () => this.speed >= 8 },
      { id: 'bombs_max', name: 'Arsenal', cond: () => this.maxBombs >= 8 },
      { id: 'range_max', name: 'Long Range', cond: () => this.blastRange >= 8 },
      { id: 'all_powerups', name: 'Fully Loaded', cond: () => this.maxBombs > 1 && this.blastRange > 2 && this.speed > 4 && this.hasPassThrough && this.hasRemoteDetonate },
      { id: 'survive_5min', name: 'Survivor', cond: () => this.timeElapsed >= 300 },
      { id: 'no_damage_level', name: 'Untouchable', cond: () => this.level > 1 && this.lives === 3 },
      { id: 'blocks_100', name: 'Wrecking Ball', cond: () => this.blocksDestroyed >= 100 },
      { id: 'blocks_500', name: 'Demolisher', cond: () => this.blocksDestroyed >= 500 },
      { id: 'enemy_bomber', name: 'Taste Your Own Medicine', cond: () => this.enemies.some(e => !e.alive && e.type === 'bomber') },
      { id: 'hard_complete', name: 'Nightmare Slayer', cond: () => this.difficulty === 2 && this.state === GameState.Victory },
      { id: 'timed_win', name: 'Speed Runner', cond: () => this.mode === GameMode.Timed && this.state === GameState.Victory },
      { id: 'survival_l5', name: 'Endurance', cond: () => this.mode === GameMode.Survival && this.level >= 5 },
      { id: 'survival_l10', name: 'Iron Will', cond: () => this.mode === GameMode.Survival && this.level >= 10 },
      { id: 'total_50k', name: 'Career: 50K', cond: () => this.totalScore >= 50000 },
      { id: 'chain_bomb', name: 'Chain Bomber', cond: () => this.comboCount >= 3 },
      { id: 'shield_save', name: 'Shield Bearer', cond: () => this.hasShield },
      { id: 'remote_kill', name: 'Remote Assassin', cond: () => this.hasRemoteDetonate && this.enemiesKilled > 0 },
      { id: 'passthrough', name: 'Ghost Walker', cond: () => this.hasPassThrough },
      { id: 'max_power', name: 'Maximum Power', cond: () => this.maxBombs >= 5 && this.blastRange >= 5 && this.speed >= 6 },
      { id: 'quick_clear', name: 'Quick Clear', cond: () => this.timeElapsed < 60 && this.enemies.every(e => !e.alive) },
      { id: 'bomb_chain_3', name: 'Triple Chain', cond: () => this.comboCount >= 3 },
      { id: 'no_bombs_die', name: 'Pacifist Death', cond: () => this.activeBombs === 0 && this.lives < 3 },
      { id: 'play_all_modes', name: 'Versatile', cond: () => this.totalGames >= 4 },
      { id: 'score_100k', name: 'Score: 100K', cond: () => this.totalScore >= 100000 },
    ];

    for (const check of checks) {
      if (!this.achievements.includes(check.id) && check.cond()) {
        this.achievements.push(check.id);
      }
    }
  }

  getAchievementName(id: string): string {
    const names: Record<string, string> = {
      first_blood: 'First Blood', bomber_10: 'Demolition Expert', combo_3: 'Chain Reaction',
      combo_5: 'Combo Master', combo_10: 'Combo Legend', score_5k: 'Score: 5000',
      score_10k: 'Score: 10000', score_50k: 'Score: 50000', level_3: 'Intermediate',
      level_5: 'Veteran', level_10: 'Master Bomber', kill_10: 'Hunter', kill_50: 'Exterminator',
      kill_100: 'Genocide', perfect: 'Perfect Clear', games_10: 'Dedicated',
      speed_max: 'Speed Demon', bombs_max: 'Arsenal', range_max: 'Long Range',
      all_powerups: 'Fully Loaded', survive_5min: 'Survivor', no_damage_level: 'Untouchable',
      blocks_100: 'Wrecking Ball', blocks_500: 'Demolisher',
      enemy_bomber: 'Taste Your Own Medicine', hard_complete: 'Nightmare Slayer',
      timed_win: 'Speed Runner', survival_l5: 'Endurance', survival_l10: 'Iron Will',
      total_50k: 'Career: 50K', chain_bomb: 'Chain Bomber', shield_save: 'Shield Bearer',
      remote_kill: 'Remote Assassin', passthrough: 'Ghost Walker', max_power: 'Maximum Power',
      quick_clear: 'Quick Clear', bomb_chain_3: 'Triple Chain',
      no_bombs_die: 'Pacifist Death', play_all_modes: 'Versatile', score_100k: 'Score: 100K',
    };
    return names[id] || id;
  }
}

import {
  createSystem,
  Mesh,
  Group,
  BoxGeometry,
  SphereGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  Vector3,
  AmbientLight,
  PointLight,
  DirectionalLight,
  FogExp2,
  AdditiveBlending,
  Float32BufferAttribute,
  BufferGeometry,
  LineBasicMaterial,
  LineSegments,
  InputComponent,
} from '@iwsdk/core';
import { GameManager, GRID_W, GRID_H, CELL_SIZE, CellType, PowerUpType, GameState, BombData, EnemyData, PowerUpData } from './game';

// Materials cache
const MAT = {
  floor: null as MeshStandardMaterial | null,
  hardBlock: null as MeshStandardMaterial | null,
  softBlock: null as MeshStandardMaterial | null,
  player: null as MeshStandardMaterial | null,
  playerGlow: null as MeshBasicMaterial | null,
  bomb: null as MeshStandardMaterial | null,
  bombGlow: null as MeshBasicMaterial | null,
  explosion: null as MeshBasicMaterial | null,
  enemyWander: null as MeshStandardMaterial | null,
  enemyChase: null as MeshStandardMaterial | null,
  enemyBomber: null as MeshStandardMaterial | null,
  gridLine: null as LineBasicMaterial | null,
  powerUp: new Map<number, MeshBasicMaterial>(),
};

// Geometries cache
const GEO = {
  cell: null as BoxGeometry | null,
  hardBlock: null as BoxGeometry | null,
  softBlock: null as BoxGeometry | null,
  player: null as CylinderGeometry | null,
  bomb: null as SphereGeometry | null,
  explosion: null as BoxGeometry | null,
  enemy: null as BoxGeometry | null,
  powerUp: null as SphereGeometry | null,
  flat: null as BoxGeometry | null,
};

function gridToWorld(gx: number, gy: number): [number, number, number] {
  const offsetX = -(GRID_W * CELL_SIZE) / 2 + CELL_SIZE / 2;
  const offsetZ = -(GRID_H * CELL_SIZE) / 2 + CELL_SIZE / 2;
  return [offsetX + gx * CELL_SIZE, 0, offsetZ + gy * CELL_SIZE];
}

export class GameSystem extends createSystem({}) {
  private game!: GameManager;
  private arenaGroup!: Group;
  private blockMeshes: Map<string, Mesh> = new Map();
  private bombMeshes: Map<string, Group> = new Map();
  private explosionMeshes: Map<string, Mesh> = new Map();
  private enemyMeshes: Map<number, Group> = new Map();
  private powerUpMeshes: Map<string, Group> = new Map();
  private playerGroup!: Group;
  private gridLines!: LineSegments;
  private lights: PointLight[] = [];
  private animTime = 0;
  private lastGridHash = '';
  private explosionParticles: Array<{ mesh: Mesh; vel: Vector3; life: number }> = [];
  private shakeTimer = 0;
  private shakeIntensity = 0;
  private cameraBasePos = new Vector3(0, 8, 6);
  private inputCooldown = 0;

  setRefs(refs: { game: GameManager }) {
    this.game = refs.game;
  }

  setupScene() {
    this.initMaterials();
    this.initGeometries();

    // Fog
    this.scene.fog = new FogExp2(0x000811, 0.04);
    this.scene.background = new Color(0x000811);

    // Lights
    const ambient = new AmbientLight(0x112244, 0.4);
    this.scene.add(ambient);

    const dirLight = new DirectionalLight(0x4488ff, 0.6);
    dirLight.position.set(5, 10, 5);
    this.scene.add(dirLight);

    // Arena group
    this.arenaGroup = new Group();
    this.scene.add(this.arenaGroup);

    // Floor
    const floorGeo = new BoxGeometry(GRID_W * CELL_SIZE + 1, 0.05, GRID_H * CELL_SIZE + 1);
    const floorMesh = new Mesh(floorGeo, MAT.floor!);
    floorMesh.position.set(0, -0.05, 0);
    this.arenaGroup.add(floorMesh);

    // Grid lines
    this.createGridLines();

    // Player
    this.playerGroup = new Group();
    const playerBody = new Mesh(GEO.player!, MAT.player!);
    playerBody.position.y = 0.4;
    this.playerGroup.add(playerBody);

    // Player glow ring
    const glowRing = new Mesh(
      new CylinderGeometry(0.35, 0.35, 0.02, 16),
      MAT.playerGlow!
    );
    glowRing.position.y = 0.05;
    this.playerGroup.add(glowRing);

    this.arenaGroup.add(this.playerGroup);
    this.playerGroup.visible = false;

    // Point lights for ambiance
    const colors = [0x00ffff, 0xff00ff, 0x00ff88];
    for (let i = 0; i < 3; i++) {
      const pl = new PointLight(colors[i], 2, 15);
      pl.position.set(
        (i - 1) * (GRID_W * CELL_SIZE / 3),
        3,
        (i - 1) * (GRID_H * CELL_SIZE / 3)
      );
      this.scene.add(pl);
      this.lights.push(pl);
    }
  }

  private initMaterials() {
    MAT.floor = new MeshStandardMaterial({ color: 0x001122, metalness: 0.8, roughness: 0.3 });
    MAT.hardBlock = new MeshStandardMaterial({ color: 0x334466, metalness: 0.6, roughness: 0.4, emissive: 0x112233, emissiveIntensity: 0.3 });
    MAT.softBlock = new MeshStandardMaterial({ color: 0x885522, metalness: 0.3, roughness: 0.6, emissive: 0x442200, emissiveIntensity: 0.2 });
    MAT.player = new MeshStandardMaterial({ color: 0x00ccff, metalness: 0.5, roughness: 0.3, emissive: 0x0066ff, emissiveIntensity: 0.5 });
    MAT.playerGlow = new MeshBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.6, blending: AdditiveBlending });
    MAT.bomb = new MeshStandardMaterial({ color: 0x222222, metalness: 0.8, roughness: 0.2, emissive: 0xff0000, emissiveIntensity: 0.3 });
    MAT.bombGlow = new MeshBasicMaterial({ color: 0xff4400, transparent: true, opacity: 0.8, blending: AdditiveBlending });
    MAT.explosion = new MeshBasicMaterial({ color: 0xff8800, transparent: true, opacity: 0.9, blending: AdditiveBlending });
    MAT.enemyWander = new MeshStandardMaterial({ color: 0xff4488, metalness: 0.4, roughness: 0.5, emissive: 0xff0044, emissiveIntensity: 0.4 });
    MAT.enemyChase = new MeshStandardMaterial({ color: 0xff0000, metalness: 0.4, roughness: 0.5, emissive: 0xff0000, emissiveIntensity: 0.6 });
    MAT.enemyBomber = new MeshStandardMaterial({ color: 0xff8800, metalness: 0.4, roughness: 0.5, emissive: 0xff4400, emissiveIntensity: 0.5 });
    MAT.gridLine = new LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.15 });

    const puColors = [0x00ff00, 0xff8800, 0xffff00, 0x8888ff, 0xff00ff, 0x00ffff];
    for (let i = 0; i < puColors.length; i++) {
      MAT.powerUp.set(i, new MeshBasicMaterial({ color: puColors[i], transparent: true, opacity: 0.9, blending: AdditiveBlending }));
    }
  }

  private initGeometries() {
    GEO.cell = new BoxGeometry(CELL_SIZE * 0.95, 0.1, CELL_SIZE * 0.95);
    GEO.hardBlock = new BoxGeometry(CELL_SIZE * 0.9, CELL_SIZE * 0.9, CELL_SIZE * 0.9);
    GEO.softBlock = new BoxGeometry(CELL_SIZE * 0.85, CELL_SIZE * 0.7, CELL_SIZE * 0.85);
    GEO.player = new CylinderGeometry(0.15, 0.25, 0.6, 8);
    GEO.bomb = new SphereGeometry(0.25, 12, 12);
    GEO.explosion = new BoxGeometry(CELL_SIZE * 0.9, 0.8, CELL_SIZE * 0.9);
    GEO.enemy = new BoxGeometry(0.45, 0.55, 0.45);
    GEO.powerUp = new SphereGeometry(0.18, 8, 8);
    GEO.flat = new BoxGeometry(CELL_SIZE * 0.9, 0.02, CELL_SIZE * 0.9);
  }

  private createGridLines() {
    const positions: number[] = [];
    const offsetX = -(GRID_W * CELL_SIZE) / 2;
    const offsetZ = -(GRID_H * CELL_SIZE) / 2;

    for (let x = 0; x <= GRID_W; x++) {
      positions.push(offsetX + x * CELL_SIZE, 0.01, offsetZ);
      positions.push(offsetX + x * CELL_SIZE, 0.01, offsetZ + GRID_H * CELL_SIZE);
    }
    for (let y = 0; y <= GRID_H; y++) {
      positions.push(offsetX, 0.01, offsetZ + y * CELL_SIZE);
      positions.push(offsetX + GRID_W * CELL_SIZE, 0.01, offsetZ + y * CELL_SIZE);
    }

    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute(positions, 3));
    this.gridLines = new LineSegments(geo, MAT.gridLine!);
    this.arenaGroup.add(this.gridLines);
  }

  update(delta: number, time: number) {
    this.animTime = time;

    if (this.game.state !== GameState.Playing) {
      this.handleMenuInput();
      return;
    }

    this.handleGameInput(delta);

    // Update game logic
    const result = this.game.update(delta);

    // Handle events
    for (const bomb of result.exploded) {
      this.onBombExplode(bomb);
    }
    for (const pos of result.destroyed) {
      this.spawnBlockDestroyEffect(pos.x, pos.y);
    }

    // Rebuild visual grid
    this.rebuildGrid();

    // Update player visual
    this.updatePlayerVisual();

    // Update enemies visual
    this.updateEnemyVisuals();

    // Update bombs visual
    this.updateBombVisuals();

    // Update explosion visuals
    this.updateExplosionVisuals();

    // Update power-up visuals
    this.updatePowerUpVisuals();

    // Update particles
    this.updateParticles(delta);

    // Camera shake
    this.updateShake(delta);

    // Animate lights
    for (let i = 0; i < this.lights.length; i++) {
      this.lights[i].intensity = 1.5 + Math.sin(time * 2 + i * 2) * 0.5;
    }
  }

  private handleGameInput(delta: number) {
    if (this.inputCooldown > 0) {
      this.inputCooldown -= delta;
      return;
    }

    const kb = this.input.keyboard;
    let dx = 0, dy = 0;

    if (kb.getKeyPressed('KeyW') || kb.getKeyPressed('ArrowUp')) dy = -1;
    else if (kb.getKeyPressed('KeyS') || kb.getKeyPressed('ArrowDown')) dy = 1;
    else if (kb.getKeyPressed('KeyA') || kb.getKeyPressed('ArrowLeft')) dx = -1;
    else if (kb.getKeyPressed('KeyD') || kb.getKeyPressed('ArrowRight')) dx = 1;

    // XR input
    const right = this.input.xr.gamepads.right;
    const left = this.input.xr.gamepads.left;
    if (left) {
      const stick = left.getAxesValues(InputComponent.Thumbstick);
      if (stick) {
        if (Math.abs(stick.x) > 0.5 || Math.abs(stick.y) > 0.5) {
          if (Math.abs(stick.x) > Math.abs(stick.y)) {
            dx = stick.x > 0 ? 1 : -1;
          } else {
            dy = stick.y > 0 ? 1 : -1;
          }
        }
      }
    }

    if (dx !== 0 || dy !== 0) {
      if (this.game.movePlayer(dx, dy, delta)) {
        this.inputCooldown = 0.12;
        this.playMoveSound();
      }
    }

    // Place bomb
    if (kb.getKeyDown('Space') || kb.getKeyDown('KeyE')) {
      if (this.game.placeBomb()) {
        this.playBombPlaceSound();
      }
    }
    if (right?.getButtonDown(InputComponent.Trigger)) {
      if (this.game.placeBomb()) {
        this.playBombPlaceSound();
      }
    }
    if (right?.getButtonDown(InputComponent.A_Button)) {
      if (this.game.placeBomb()) {
        this.playBombPlaceSound();
      }
    }

    // Remote detonate
    if (kb.getKeyDown('KeyR') || right?.getButtonDown(InputComponent.B_Button)) {
      this.game.detonateRemote();
    }

    // Pause
    if (kb.getKeyDown('Escape') || left?.getButtonDown(InputComponent.B_Button)) {
      this.game.state = GameState.Paused;
    }
  }

  private handleMenuInput() {
    // Simple keyboard shortcuts for menu navigation handled by UI system
  }

  private rebuildGrid() {
    // Compute grid hash to avoid rebuilding every frame
    let hash = '';
    for (let y = 0; y < GRID_H; y++) {
      for (let x = 0; x < GRID_W; x++) {
        hash += this.game.grid[y][x];
      }
    }
    if (hash === this.lastGridHash) return;
    this.lastGridHash = hash;

    // Remove stale meshes
    const activeKeys = new Set<string>();

    for (let y = 0; y < GRID_H; y++) {
      for (let x = 0; x < GRID_W; x++) {
        const cell = this.game.grid[y][x];
        const key = `${x}_${y}`;
        const [wx, , wz] = gridToWorld(x, y);

        if (cell === CellType.HardBlock) {
          activeKeys.add(key);
          if (!this.blockMeshes.has(key)) {
            const mesh = new Mesh(GEO.hardBlock!, MAT.hardBlock!);
            mesh.position.set(wx, CELL_SIZE * 0.45, wz);
            this.arenaGroup.add(mesh);
            this.blockMeshes.set(key, mesh);
          }
        } else if (cell === CellType.SoftBlock) {
          activeKeys.add(key);
          if (!this.blockMeshes.has(key)) {
            const mesh = new Mesh(GEO.softBlock!, MAT.softBlock!);
            mesh.position.set(wx, CELL_SIZE * 0.35, wz);
            this.arenaGroup.add(mesh);
            this.blockMeshes.set(key, mesh);
          }
        }
      }
    }

    // Clean up removed blocks
    for (const [key, mesh] of this.blockMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(mesh);
        this.blockMeshes.delete(key);
      }
    }
  }

  private updatePlayerVisual() {
    const [wx, , wz] = gridToWorld(this.game.playerVisualX, this.game.playerVisualY);
    this.playerGroup.position.set(wx, 0, wz);
    this.playerGroup.visible = true;

    // Shield effect
    if (this.game.hasShield && this.game.shieldTimer > 0) {
      const pulse = Math.sin(this.animTime * 8) * 0.2 + 0.8;
      MAT.playerGlow!.opacity = pulse * 0.8;
      MAT.playerGlow!.color.setHex(0x00ffff);
    } else {
      MAT.playerGlow!.opacity = 0.4 + Math.sin(this.animTime * 3) * 0.2;
      MAT.playerGlow!.color.setHex(0x00ffff);
    }

    // Rotate player
    this.playerGroup.rotation.y = this.animTime * 0.5;
  }

  private updateBombVisuals() {
    const activeKeys = new Set<string>();

    for (const bomb of this.game.bombs) {
      const key = `${bomb.x}_${bomb.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(bomb.x, bomb.y);

      if (!this.bombMeshes.has(key)) {
        const group = new Group();
        const body = new Mesh(GEO.bomb!, MAT.bomb!);
        body.position.y = 0.3;
        group.add(body);

        const glow = new Mesh(
          new SphereGeometry(0.32, 8, 8),
          MAT.bombGlow!.clone()
        );
        glow.position.y = 0.3;
        group.add(glow);

        group.position.set(wx, 0, wz);
        this.arenaGroup.add(group);
        this.bombMeshes.set(key, group);
      }

      const group = this.bombMeshes.get(key)!;
      // Pulse faster as timer decreases
      const urgency = 1 - bomb.timer / 3;
      const pulse = Math.sin(this.animTime * (5 + urgency * 15)) * 0.5 + 0.5;
      const glow = group.children[1] as Mesh;
      (glow.material as MeshBasicMaterial).opacity = 0.3 + pulse * 0.5;
      group.children[0].scale.setScalar(0.9 + pulse * 0.15);

      // Color shift to brighter red near detonation
      const emissiveIntensity = 0.3 + urgency * 0.7;
      (group.children[0] as Mesh).material = MAT.bomb!;
      MAT.bomb!.emissiveIntensity = emissiveIntensity;
    }

    // Remove detonated bombs
    for (const [key, group] of this.bombMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(group);
        this.bombMeshes.delete(key);
      }
    }
  }

  private updateExplosionVisuals() {
    const activeKeys = new Set<string>();

    for (const exp of this.game.explosions) {
      const key = `${exp.x}_${exp.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(exp.x, exp.y);

      if (!this.explosionMeshes.has(key)) {
        const mesh = new Mesh(GEO.explosion!, MAT.explosion!.clone());
        mesh.position.set(wx, 0.4, wz);
        this.arenaGroup.add(mesh);
        this.explosionMeshes.set(key, mesh);
      }

      const mesh = this.explosionMeshes.get(key)!;
      const life = exp.timer / 0.5;
      mesh.scale.setScalar(0.5 + life * 0.5);
      (mesh.material as MeshBasicMaterial).opacity = life * 0.9;

      // Color shift from white-hot to orange
      const c = new Color();
      c.setHSL(0.08 * life, 1, 0.5 + life * 0.3);
      (mesh.material as MeshBasicMaterial).color = c;
    }

    for (const [key, mesh] of this.explosionMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(mesh);
        this.explosionMeshes.delete(key);
      }
    }
  }

  private updateEnemyVisuals() {
    const activeIds = new Set<number>();

    for (let i = 0; i < this.game.enemies.length; i++) {
      const enemy = this.game.enemies[i];
      if (!enemy.alive) {
        if (this.enemyMeshes.has(i)) {
          this.arenaGroup.remove(this.enemyMeshes.get(i)!);
          this.enemyMeshes.delete(i);
        }
        continue;
      }
      activeIds.add(i);
      const [wx, , wz] = gridToWorld(enemy.visualX, enemy.visualY);

      if (!this.enemyMeshes.has(i)) {
        const group = new Group();
        const mat = enemy.type === 'chase' ? MAT.enemyChase! :
          enemy.type === 'bomber' ? MAT.enemyBomber! : MAT.enemyWander!;
        const body = new Mesh(GEO.enemy!, mat);
        body.position.y = 0.35;
        group.add(body);

        // Eyes
        const eyeMat = new MeshBasicMaterial({ color: 0xffffff });
        const eyeGeo = new SphereGeometry(0.06, 6, 6);
        const eye1 = new Mesh(eyeGeo, eyeMat);
        eye1.position.set(-0.1, 0.45, -0.22);
        group.add(eye1);
        const eye2 = new Mesh(eyeGeo, eyeMat);
        eye2.position.set(0.1, 0.45, -0.22);
        group.add(eye2);

        this.arenaGroup.add(group);
        this.enemyMeshes.set(i, group);
      }

      const group = this.enemyMeshes.get(i)!;
      group.position.set(wx, 0, wz);

      // Bob animation
      group.children[0].position.y = 0.35 + Math.sin(this.animTime * 4 + i) * 0.05;
      group.rotation.y = Math.sin(this.animTime * 2 + i * 3) * 0.3;
    }

    // Clean up dead enemies
    for (const [id, group] of this.enemyMeshes) {
      if (!activeIds.has(id)) {
        this.arenaGroup.remove(group);
        this.enemyMeshes.delete(id);
      }
    }
  }

  private updatePowerUpVisuals() {
    const activeKeys = new Set<string>();

    for (const pu of this.game.powerUps) {
      if (pu.collected) continue;
      const key = `${pu.x}_${pu.y}`;
      activeKeys.add(key);
      const [wx, , wz] = gridToWorld(pu.x, pu.y);

      if (!this.powerUpMeshes.has(key)) {
        const group = new Group();
        const mat = MAT.powerUp.get(pu.type) || MAT.powerUp.get(0)!;
        const sphere = new Mesh(GEO.powerUp!, mat);
        sphere.position.y = 0.4;
        group.add(sphere);

        // Ring around power-up
        const ring = new Mesh(
          new CylinderGeometry(0.25, 0.25, 0.02, 12),
          mat.clone()
        );
        ring.position.y = 0.15;
        group.add(ring);

        group.position.set(wx, 0, wz);
        this.arenaGroup.add(group);
        this.powerUpMeshes.set(key, group);
      }

      const group = this.powerUpMeshes.get(key)!;
      // Float and spin
      group.children[0].position.y = 0.4 + Math.sin(this.animTime * 3) * 0.1;
      group.children[0].rotation.y = this.animTime * 2;
      group.children[1].rotation.y = -this.animTime * 1.5;
    }

    for (const [key, group] of this.powerUpMeshes) {
      if (!activeKeys.has(key)) {
        this.arenaGroup.remove(group);
        this.powerUpMeshes.delete(key);
      }
    }
  }

  private onBombExplode(bomb: BombData) {
    this.shakeTimer = 0.3;
    this.shakeIntensity = 0.15;
    this.playExplosionSound();
  }

  private spawnBlockDestroyEffect(gx: number, gy: number) {
    const [wx, , wz] = gridToWorld(gx, gy);
    for (let i = 0; i < 6; i++) {
      const size = 0.05 + Math.random() * 0.1;
      const geo = new BoxGeometry(size, size, size);
      const mat = new MeshBasicMaterial({
        color: new Color().setHSL(0.08 + Math.random() * 0.05, 0.8, 0.5),
        transparent: true,
        opacity: 1,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.set(
        wx + (Math.random() - 0.5) * 0.3,
        0.3 + Math.random() * 0.3,
        wz + (Math.random() - 0.5) * 0.3
      );
      this.arenaGroup.add(mesh);
      this.explosionParticles.push({
        mesh,
        vel: new Vector3(
          (Math.random() - 0.5) * 3,
          2 + Math.random() * 3,
          (Math.random() - 0.5) * 3
        ),
        life: 0.8 + Math.random() * 0.4,
      });
    }
  }

  private updateParticles(delta: number) {
    for (let i = this.explosionParticles.length - 1; i >= 0; i--) {
      const p = this.explosionParticles[i];
      p.life -= delta;
      if (p.life <= 0) {
        this.arenaGroup.remove(p.mesh);
        this.explosionParticles.splice(i, 1);
        continue;
      }
      p.vel.y -= 9.8 * delta;
      p.mesh.position.add(p.vel.clone().multiplyScalar(delta));
      (p.mesh.material as MeshBasicMaterial).opacity = p.life;
      p.mesh.rotation.x += delta * 5;
      p.mesh.rotation.z += delta * 3;
    }
  }

  private updateShake(delta: number) {
    if (this.shakeTimer > 0) {
      this.shakeTimer -= delta;
      const shake = this.shakeIntensity * (this.shakeTimer / 0.3);
      this.camera.position.set(
        this.cameraBasePos.x + (Math.random() - 0.5) * shake,
        this.cameraBasePos.y + (Math.random() - 0.5) * shake * 0.5,
        this.cameraBasePos.z + (Math.random() - 0.5) * shake
      );
    }
  }

  showGame() {
    this.playerGroup.visible = true;
    this.arenaGroup.visible = true;
    this.lastGridHash = ''; // Force rebuild
  }

  hideGame() {
    this.playerGroup.visible = false;
    // Clean up all meshes
    for (const [, mesh] of this.blockMeshes) this.arenaGroup.remove(mesh);
    this.blockMeshes.clear();
    for (const [, mesh] of this.bombMeshes) this.arenaGroup.remove(mesh);
    this.bombMeshes.clear();
    for (const [, mesh] of this.explosionMeshes) this.arenaGroup.remove(mesh);
    this.explosionMeshes.clear();
    for (const [, mesh] of this.enemyMeshes) this.arenaGroup.remove(mesh);
    this.enemyMeshes.clear();
    for (const [, mesh] of this.powerUpMeshes) this.arenaGroup.remove(mesh);
    this.powerUpMeshes.clear();
    this.lastGridHash = '';
  }

  applyTheme() {
    const theme = this.game.currentTheme;
    MAT.floor!.color.setHex(theme.floorColor);
    MAT.gridLine!.color.setHex(theme.gridColor);
    MAT.playerGlow!.color.setHex(theme.accentColor);
    this.scene.background = new Color(theme.floorColor);
    if (this.scene.fog) {
      (this.scene.fog as FogExp2).color.setHex(theme.floorColor);
    }
  }

  // --- Procedural audio ---
  private audioCtx: AudioContext | null = null;

  private getAudioCtx(): AudioContext {
    if (!this.audioCtx) {
      this.audioCtx = new AudioContext();
    }
    return this.audioCtx;
  }

  private playTone(freq: number, duration: number, volume: number, type: OscillatorType = 'square') {
    try {
      const ctx = this.getAudioCtx();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = type;
      osc.frequency.setValueAtTime(freq, ctx.currentTime);
      gain.gain.setValueAtTime(volume * this.game.sfxVolume, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + duration);
    } catch { /* audio may not be available */ }
  }

  private playNoise(duration: number, volume: number) {
    try {
      const ctx = this.getAudioCtx();
      const bufferSize = Math.floor(ctx.sampleRate * duration);
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / bufferSize, 2);
      }
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      const gain = ctx.createGain();
      gain.gain.setValueAtTime(volume * this.game.sfxVolume, ctx.currentTime);
      source.connect(gain);
      gain.connect(ctx.destination);
      source.start();
    } catch { /* audio may not be available */ }
  }

  playMoveSound() {
    this.playTone(440, 0.05, 0.1, 'sine');
  }

  playBombPlaceSound() {
    this.playTone(220, 0.15, 0.2, 'square');
    this.playTone(165, 0.2, 0.15, 'square');
  }

  playExplosionSound() {
    this.playNoise(0.4, 0.4);
    this.playTone(80, 0.3, 0.3, 'sawtooth');
  }

  playPowerUpSound() {
    this.playTone(660, 0.1, 0.15, 'sine');
    setTimeout(() => this.playTone(880, 0.1, 0.15, 'sine'), 50);
    setTimeout(() => this.playTone(1100, 0.15, 0.12, 'sine'), 100);
  }

  playDeathSound() {
    this.playTone(440, 0.15, 0.3, 'sawtooth');
    setTimeout(() => this.playTone(330, 0.15, 0.25, 'sawtooth'), 100);
    setTimeout(() => this.playTone(220, 0.3, 0.2, 'sawtooth'), 200);
  }

  playVictorySound() {
    const notes = [523, 659, 784, 1047];
    notes.forEach((n, i) => {
      setTimeout(() => this.playTone(n, 0.2, 0.15, 'sine'), i * 150);
    });
  }
}

import {
  createSystem,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  UIKit,
  eq,
  Entity,
} from '@iwsdk/core';
import { GameManager, GameState, GameMode } from './game';
import { GameSystem } from './game-system';

const getDoc = (e: Entity) =>
  e.getValue(PanelDocument, 'document') as UIKitDocument | undefined;

const setText = (doc: UIKitDocument | undefined, id: string, text: string) =>
  (doc?.getElementById(id) as any)?.setProperties({ text });

const onClick = (doc: UIKitDocument, id: string, cb: () => void) => {
  const el = doc.getElementById(id) as any;
  el?.addEventListener('click', cb);
};

export class GameUISystem extends createSystem({
  hud: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/hud.json')],
  },
  menu: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/menu.json')],
  },
  gameover: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/gameover.json')],
  },
  settings: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/settings.json')],
  },
}) {
  private game!: GameManager;
  private gameSystem!: GameSystem;
  private hudEntity!: Entity;
  private menuEntity!: Entity;
  private gameoverEntity!: Entity;
  private settingsEntity!: Entity;
  private hudDoc: UIKitDocument | null = null;
  private menuDoc: UIKitDocument | null = null;
  private gameoverDoc: UIKitDocument | null = null;
  private settingsDoc: UIKitDocument | null = null;
  private lastState: GameState = GameState.Menu;

  setRefs(refs: { game: GameManager; gameSystem: GameSystem }) {
    this.game = refs.game;
    this.gameSystem = refs.gameSystem;
  }

  setPanelEntities(hud: Entity, menu: Entity, gameover: Entity, settings: Entity) {
    this.hudEntity = hud;
    this.menuEntity = menu;
    this.gameoverEntity = gameover;
    this.settingsEntity = settings;
  }

  init() {
    this.queries.hud.subscribe('qualify', (entity) => {
      this.hudDoc = getDoc(entity) || null;
    });

    this.queries.menu.subscribe('qualify', (entity) => {
      this.menuDoc = getDoc(entity) || null;
      if (this.menuDoc) this.wireMenuButtons();
    });

    this.queries.gameover.subscribe('qualify', (entity) => {
      this.gameoverDoc = getDoc(entity) || null;
      if (this.gameoverDoc) this.wireGameoverButtons();
    });

    this.queries.settings.subscribe('qualify', (entity) => {
      this.settingsDoc = getDoc(entity) || null;
      if (this.settingsDoc) this.wireSettingsButtons();
    });
  }

  private wireMenuButtons() {
    const doc = this.menuDoc!;

    onClick(doc, 'btn-classic', () => {
      this.game.startGame(GameMode.Classic);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-timed', () => {
      this.game.startGame(GameMode.Timed);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-survival', () => {
      this.game.startGame(GameMode.Survival);
      this.gameSystem.showGame();
      this.gameSystem.applyTheme();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-settings', () => {
      this.showPanel('settings');
    });
  }

  private wireGameoverButtons() {
    const doc = this.gameoverDoc!;

    onClick(doc, 'btn-retry', () => {
      this.game.startGame(this.game.mode);
      this.gameSystem.showGame();
      this.showPanel('playing');
    });

    onClick(doc, 'btn-menu', () => {
      this.game.state = GameState.Menu;
      this.gameSystem.hideGame();
      this.showPanel('menu');
    });
  }

  private wireSettingsButtons() {
    const doc = this.settingsDoc!;

    onClick(doc, 'btn-back', () => {
      this.showPanel('menu');
    });

    onClick(doc, 'btn-easy', () => {
      this.game.difficulty = 0;
      this.updateSettingsDisplay();
    });

    onClick(doc, 'btn-normal', () => {
      this.game.difficulty = 1;
      this.updateSettingsDisplay();
    });

    onClick(doc, 'btn-hard', () => {
      this.game.difficulty = 2;
      this.updateSettingsDisplay();
    });

    for (let i = 0; i < this.game.themes.length; i++) {
      onClick(doc, `btn-theme-${i}`, () => {
        this.game.themeIndex = i;
        this.gameSystem.applyTheme();
        this.updateSettingsDisplay();
      });
    }
  }

  private updateSettingsDisplay() {
    if (!this.settingsDoc) return;
    const diffNames = ['Easy', 'Normal', 'Hard'];
    setText(this.settingsDoc, 'diff-label', `Difficulty: ${diffNames[this.game.difficulty]}`);
    setText(this.settingsDoc, 'theme-label', `Theme: ${this.game.currentTheme.name}`);
  }

  private showPanel(state: 'menu' | 'playing' | 'gameover' | 'settings' | 'victory') {
    if (this.menuEntity) this.menuEntity.object3D!.visible = state === 'menu';
    if (this.gameoverEntity) this.gameoverEntity.object3D!.visible = state === 'gameover' || state === 'victory';
    if (this.settingsEntity) this.settingsEntity.object3D!.visible = state === 'settings';
    if (this.hudEntity) this.hudEntity.object3D!.visible = state === 'playing';
  }

  update(delta: number, time: number) {
    if (this.game.state !== this.lastState) {
      this.onStateChange(this.lastState, this.game.state);
      this.lastState = this.game.state;
    }

    if (this.game.state === GameState.Playing && this.hudDoc) {
      this.updateHUD();
    }

    if (this.game.state === GameState.Paused) {
      if (this.input.keyboard.getKeyDown('Escape')) {
        this.game.state = GameState.Playing;
        this.showPanel('playing');
      }
    }
  }

  private onStateChange(from: GameState, to: GameState) {
    if (to === GameState.GameOver) {
      this.showPanel('gameover');
      this.updateGameoverDisplay(false);
      this.gameSystem.playDeathSound();
    } else if (to === GameState.Victory) {
      this.showPanel('victory');
      this.updateGameoverDisplay(true);
      this.gameSystem.playVictorySound();
    } else if (to === GameState.Paused) {
      this.showPanel('menu');
    } else if (to === GameState.Menu) {
      this.showPanel('menu');
    }
  }

  private updateHUD() {
    if (!this.hudDoc) return;
    setText(this.hudDoc, 'score', `Score: ${Math.floor(this.game.score)}`);
    setText(this.hudDoc, 'lives', `Lives: ${this.game.lives}`);
    setText(this.hudDoc, 'level', `Lv ${this.game.level}`);

    if (this.game.mode === GameMode.Timed) {
      const remaining = Math.max(0, this.game.timeLimit - this.game.timeElapsed);
      const min = Math.floor(remaining / 60);
      const sec = Math.floor(remaining % 60);
      setText(this.hudDoc, 'timer', `${min}:${sec.toString().padStart(2, '0')}`);
    } else {
      const min = Math.floor(this.game.timeElapsed / 60);
      const sec = Math.floor(this.game.timeElapsed % 60);
      setText(this.hudDoc, 'timer', `${min}:${sec.toString().padStart(2, '0')}`);
    }

    if (this.game.comboCount > 1) {
      setText(this.hudDoc, 'combo', `x${this.game.comboCount} COMBO`);
    } else {
      setText(this.hudDoc, 'combo', '');
    }
  }

  private updateGameoverDisplay(victory: boolean) {
    if (!this.gameoverDoc) return;
    setText(this.gameoverDoc, 'title', victory ? 'VICTORY!' : 'GAME OVER');
    setText(this.gameoverDoc, 'final-score', `Score: ${Math.floor(this.game.score)}`);
    setText(this.gameoverDoc, 'stats', `Level ${this.game.level} -- Enemies: ${this.game.enemiesKilled} -- Blocks: ${this.game.blocksDestroyed}`);
    setText(this.gameoverDoc, 'best-score', `Best: ${Math.floor(this.game.bestScore)}`);

    const newAchievements = this.game.achievements.slice(-3);
    if (newAchievements.length > 0) {
      const names = newAchievements.map(id => this.game.getAchievementName(id)).join(', ');
      setText(this.gameoverDoc, 'achievements', `Unlocked: ${names}`);
    } else {
      setText(this.gameoverDoc, 'achievements', `Achievements: ${this.game.achievements.length}/40`);
    }
  }
}

import {
  World,
  PanelUI,
  Follower,
} from '@iwsdk/core';

async function main() {
  const container = document.getElementById('app') as HTMLDivElement;

  const world = await World.create(container, {
    xr: { offer: 'once' },
    input: { canvasPointerEvents: true },
    render: {
      near: 0.01,
      far: 200,
      defaultLighting: false,
      camera: { position: [0, 8, 6], lookAt: [0, 0, 0] },
    },
    features: {
      grabbing: false,
      locomotion: { browserControls: true },
      physics: false,
      spatialUI: true,
    },
  });

  // Import systems dynamically to keep index clean
  const { GameManager } = await import('./game');
  const { GameSystem } = await import('./game-system');
  const { GameUISystem } = await import('./ui-system');

  const game = new GameManager();

  // Register systems
  world.registerSystem(GameSystem);
  world.registerSystem(GameUISystem);

  const gameSystem = world.getSystem(GameSystem)!;
  gameSystem.setRefs({ game });

  const uiSystem = world.getSystem(GameUISystem)!;
  uiSystem.setRefs({ game, gameSystem });

  // Setup scene
  gameSystem.setupScene();

  // Create HUD panel (head-locked)
  const hudEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  hudEntity.addComponent(PanelUI, { config: './ui/hud.json' });
  hudEntity.addComponent(Follower);
  const fOff = hudEntity.getVectorView(Follower, 'offsetPosition');
  fOff[0] = 0; fOff[1] = 0.22; fOff[2] = -0.6;

  // Create menu panel (world-space, in front of player)
  const menuEntity = world.createTransformEntity();
  menuEntity.object3D!.position.set(0, 4, -2);
  menuEntity.addComponent(PanelUI, { config: './ui/menu.json' });

  // Create game-over panel (world-space, hidden initially)
  const gameoverEntity = world.createTransformEntity();
  gameoverEntity.object3D!.position.set(0, 4, -2);
  gameoverEntity.object3D!.visible = false;
  gameoverEntity.addComponent(PanelUI, { config: './ui/gameover.json' });

  // Create settings panel
  const settingsEntity = world.createTransformEntity();
  settingsEntity.object3D!.position.set(0, 4, -2);
  settingsEntity.object3D!.visible = false;
  settingsEntity.addComponent(PanelUI, { config: './ui/settings.json' });

  uiSystem.setPanelEntities(hudEntity, menuEntity, gameoverEntity, settingsEntity);
}

main();

